import styles from "./Activity.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import { connect } from "react-redux";
import includes from "lodash/includes";
import buildActions from "../../../store/actions";
import { InjectLocale } from "../../../../../decorators/locale";
import { DragNDrop } from "../../../../../decorators/dnd";
import { dropZoneStyles } from "../../../../common/components/DropZone/DropZone";
import { getBounds } from "../../../../../utils/bounds";
import { trapTabKey } from "../../../../../utils/accessibility";
import { Key } from "../../../../../../common/constants/keyboard";
import { Classes } from "../../../../../../common/constants/classes";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { Buttons } from "../../../../../constants/buttons";
import DragItem from "../../../../common/components/DragItem/DragItem";
import Zone from "../Zone/Zone";

@connect(
  state => ({
    ...state,
    activityId: state.id,
    activityType: state.type
  }),
  buildActions
)
@InjectLocale("Activity")
@DragNDrop
class Activity extends PureComponent {
  static propTypes = {
    activityId: PropTypes.number.isRequired,
    activityType: PropTypes.string.isRequired,
    zones: PropTypes.arrayOf(PropTypes.object),
    items: PropTypes.arrayOf(PropTypes.object),
    setPosition: PropTypes.func.isRequired,
    disableItem: PropTypes.func.isRequired,
    resetPosition: PropTypes.func.isRequired,
    setCorrect: PropTypes.func.isRequired,
    setDetached: PropTypes.func.isRequired,
    restart: PropTypes.func.isRequired,
    score: PropTypes.number
  };

  dragContainer;
  shift;

  activeDropZoneSelector = `.${styles.container} .${dropZoneStyles.container}:not(.${
    dropZoneStyles.correct
  })`;

  state = {
    animationClass: "",
    itemSize: {
      width: 100,
      height: 60
    }
  };

  handleStop = data => {
    const { zones } = this.props;
    const dragItemId = this.state.currentItemId;
    const dragItemIndex = this.state.currentItemIndex;
    const { inPlayerPos, initialPos } = data;
    let correctDrop = false;
    let dropZoneIndex;

    this.dropZones.forEach((item, index) => {
      if (
        inPlayerPos.x > item.left &&
        inPlayerPos.x < item.right &&
        inPlayerPos.y > item.top &&
        inPlayerPos.y < item.bottom &&
        dragItemId === zones[index].id
      ) {
        correctDrop = true;
        dropZoneIndex = index;
      }
    });

    if (correctDrop) {
      this.props.setPosition(dragItemIndex, {
        left: this.dropZones[dropZoneIndex].left - this.dragItems[dragItemIndex].left,
        top: this.dropZones[dropZoneIndex].top - this.dragItems[dragItemIndex].top
      });
      this.handleCorrectDrop(dragItemIndex, dropZoneIndex);
    } else {
      this.props.setPosition(dragItemIndex, initialPos);
      this.handleIncorrectDrop(dragItemIndex);
    }

    this.setState({
      currentItemIndex: null,
      currentItemId: null,
      activeZoneIndex: null,
      transitionItemIndexes: this.state.transitionItemIndexes.concat(dragItemIndex)
    });

    this.zoneOffsets.forEach((item, index) => {
      if (
        inPlayerPos.x > item.left &&
        inPlayerPos.x < item.right &&
        inPlayerPos.y > item.top &&
        inPlayerPos.y < item.bottom &&
        dragItemId === zones[index].id
      ) {
        correctDrop = true;
        dropZoneIndex = index;
      }
    });
  };

  handleCorrectDrop = (dragItemIndex, dropZoneIndex) => {
    this.props.disableItem(dragItemIndex);
    this.setState({
      correctZoneIndexes: this.state.correctZoneIndexes.concat(dropZoneIndex)
    });
  };

  handleIncorrectDrop = dragItemIndex => {
    this.setState({
      transitionItemIndexes: this.state.transitionItemIndexes.concat(dragItemIndex)
    });
    this.props.resetPosition(dragItemIndex);
  };

  handleKeyboardShift = (e, pos) => {
    e.preventDefault();
    const dragItemIndex = this.state.currentItemIndex;
    const dragItemBounds = getBounds(e.target);
    let hitZone = false;

    this.props.setPosition(dragItemIndex, pos);
    this.dropZones.forEach((item, index) => {
      if (
        ((dragItemBounds.right > item.left + item.width / 2 && dragItemBounds.right < item.right) ||
          (dragItemBounds.left < item.left + item.width / 2 && dragItemBounds.left > item.left)) &&
        ((dragItemBounds.bottom > item.top + item.height / 2 &&
          dragItemBounds.bottom < item.bottom) ||
          (dragItemBounds.top < item.top + item.height / 2 && dragItemBounds.top > item.top))
      ) {
        hitZone = true;
        this.setState({
          activeZoneIndex: index
        });
      }
    });

    if (!hitZone && this.state.activeZoneIndex !== null) {
      this.setState({
        activeZoneIndex: null
      });
    }
  };

  initDropZones = () => {
    const dropZones = Array.from(
      document.querySelectorAll(`.${styles.container} .${dropZoneStyles.container}`)
    );

    dropZones.forEach((item, index) => {
      const bounds = getBounds(item);

      this.dropZones[index] = Object.assign({}, bounds);
    });
  };

  restart = () => {
    this.setState({
      correctZoneIndexes: [],
      ariaText: this.locale.restart
    });
    this.props.restart();
  };

  onAnimationEnd = () => {
    this.setState({
      animationClass: ""
    });
  };

  onBodyKeyDown = e => {
    if (e.keyCode === Key.TAB) {
      trapTabKey(e);
    }
  };

  get dragItemsBlock() {
    const { currentItemIndex, transitionItemIndexes, notFocusable } = this.state;

    return (
      <div className={styles.items}>
        {this.props.items.map((item, index) => {
          const active = index === currentItemIndex;
          const transition = includes(transitionItemIndexes, index);
          const disabled =
            item.disabled ||
            (transitionItemIndexes.length !== 0 && !includes(transitionItemIndexes, index));

          return (
            <DragItem
              key={index}
              index={index}
              notFocusable={notFocusable}
              active={active}
              transition={transition}
              disabled={disabled}
              value={item.value}
              position={item.position}
              onStart={this.handleStart}
              onStop={this.handleStop}
              onDrag={this.handleDrag}
              onKeyDown={this.onDragItemKeyDown}
              onFocus={this.onDragItemFocus}
              onTransitionEnd={this.onTransitionEnd}
              correct={item.correct}
              detached={item.detached}
              parentSelector={`.${styles.player}`}
              size={this.state.itemSize}
            />
          );
        })}
      </div>
    );
  }

  render() {
    return (
      <section
        role="application"
        tabIndex="0"
        className={styles.container}
        onKeyDown={this.onActivityKeyDown}
      >
        <span className={Classes.VISUALLY_HIDDEN} aria-live="polite" aria-atomic="true">
          {this.state.ariaText}
        </span>
        <div
          className={classNames(styles.player, this.state.animationClass)}
          onAnimationEnd={this.onAnimationEnd}
          ref={element => (this.dragContainer = element)}
        >
          <div className={styles.wrapper}>
            <div className={styles.body} onKeyDown={this.onBodyKeyDown}>
              {this.props.zones.map((item, index) => (
                <Zone
                  correctZone={includes(this.state.correctZoneIndexes, index)}
                  activeZone={index === this.state.activeZoneIndex}
                  key={index}
                  index={index}
                  item={item}
                  notFocusable={this.state.notFocusable}
                  onDropZoneKeyDown={this.onDropZoneKeyDown}
                  items={this.props.items}
                  complete={this.state.complete}
                  onCorrectSelect={this.handleCorrectDrop}
                  onIncorrectSelect={this.handleIncorrectDrop}
                  zoneOffsets={this.dropZones[index]}
                  itemSize={this.state.itemSize}
                />
              ))}
            </div>
            {this.dragItemsBlock}
          </div>
          <Button
            id={Buttons.RESTART}
            notFocusable={this.state.notFocusable}
            className={buttonStyles.restart}
            onFocus={this.onButtonFocus}
            onClick={this.restart}
          >
            Re-start
          </Button>
        </div>
      </section>
    );
  }
}

export default Activity;
