import cloneDeep from "lodash/cloneDeep";
import types from "./types";

export default {
  [types.SET_POSITION](state, action) {
    let stateClone = cloneDeep(state);
    const index = +action.index;

    stateClone.items[index].position.x += action.shift.x;
    stateClone.items[index].position.y += action.shift.y;

    return stateClone;
  },
  [types.RESET_POSITION](state, action) {
    let stateClone = cloneDeep(state);
    const index = +action.index;

    stateClone.items[index].position = {
      x: 0,
      y: 0
    };

    return stateClone;
  },
  [types.DISABLE_ITEM](state, action) {
    let stateClone = cloneDeep(state);
    const index = +action.index;

    stateClone.items[index].disabled = true;

    return stateClone;
  },
  [types.RESTART](state) {
    return {
      ...state,
      items: cloneDeep(state.initialItems)
    };
  },
  [types.SET_DETACHED](state, action) {
    const items = [...state.items];

    items[action.index] = {
      ...items[action.index],
      detached: action.val
    };

    return {
      ...state,
      items
    };
  },
  [types.SET_CORRECT](state, action) {
    const items = [...state.items];
    const { index, correct } = action;

    items[index] = {
      ...items[index],
      correct,
      disabled: correct ? true : items[index].disabled,
      mistakes: !correct ? items[index].mistakes + 1 : items[index].mistakes
    };

    return {
      ...state,
      items
    };
  }
};
