import styles from "./Zone.module.scss";
import classNames from "classnames";
import PropTypes from "prop-types";
import React, { PureComponent } from "react";
import DropZone from "../../../../common/components/DropZone/DropZone";

export default class Zone extends PureComponent {
  static propTypes = {
    items: PropTypes.arrayOf(PropTypes.object),
    item: PropTypes.object.isRequired,
    itemSize: PropTypes.object.isRequired,
    activeZone: PropTypes.bool.isRequired,
    correctZone: PropTypes.bool.isRequired,
    complete: PropTypes.bool.isRequired,
    index: PropTypes.number.isRequired,
    notFocusable: PropTypes.bool.isRequired,
    zoneOffsets: PropTypes.object.isRequired,
    onDropZoneKeyDown: PropTypes.func.isRequired,
    handleCorrectDrop: PropTypes.func.isRequired,
    handleIncorrectDrop: PropTypes.func.isRequired
  };

  render() {
    const {
      items,
      item,
      correctZone,
      activeZone,
      index,
      notFocusable,
      onDropZoneKeyDown,
      zoneOffsets,
      complete,
      itemSize,
      handleCorrectDrop,
      handleIncorrectDrop
    } = this.props;

    return (
      <div className={styles.container}>
        <div className={styles.term}>{item.value}</div>
        <div className={styles["line-container"]}>
          <div className={styles.line} />
          <div
            className={classNames(
              styles["line-background"],
              correctZone && styles["line-background-active"]
            )}
          />
        </div>
        <DropZone
          notFocusable={notFocusable}
          value={item.value}
          index={index}
          active={activeZone}
          correct={correctZone}
          onKeyDown={onDropZoneKeyDown}
          items={items}
          id={item.id}
          complete={complete}
          size={itemSize}
          onCorrectSelect={handleCorrectDrop}
          onIncorrectSelect={handleIncorrectDrop}
          {...zoneOffsets}
          {...item}
        />
      </div>
    );
  }
}
