import shuffle from "lodash/shuffle";
import cloneDeep from "lodash/cloneDeep";

export default state => {
  const terms = [];
  const items = [];

  state.items.forEach((item, index) => {
    terms.push({
      id: index,
      value: item.term
    });

    items.push({
      id: index,
      value: item.definition,
      disabled: false,
      position: {
        x: 0,
        y: 0
      }
    });
  });

  const shuffledItems = shuffle(items);

  return {
    ...state,
    zones: items,
    terms: shuffle(terms),
    items: shuffledItems,
    initialItems: cloneDeep(shuffledItems)
  };
};
