import { bindActionCreators } from "redux";
import types from "./types";

export const actions = {
  setPosition(index, shift) {
    return {
      type: types.SET_POSITION,
      index,
      shift
    };
  },
  resetPosition(index) {
    return {
      type: types.RESET_POSITION,
      index
    };
  },
  disableItem(index) {
    return {
      type: types.DISABLE_ITEM,
      index
    };
  },
  restart() {
    return {
      type: types.RESTART
    };
  },
  setCorrect(index, correct) {
    return {
      type: types.SET_CORRECT,
      index,
      correct
    };
  },
  setDetached(index, val) {
    return {
      type: types.SET_DETACHED,
      index,
      val
    };
  }
};

export default dispatcher => bindActionCreators(actions, dispatcher);
